{"contents":"<script setup lang="ts">
import { ref, watch, onMounted, onBeforeUnmount, shallowRef } from 'vue'
import * as echarts from 'echarts'
import type { KnowledgeNode, GraphEdge } from '@/types'

const props = defineProps<{
  nodes: KnowledgeNode[]
  edges: GraphEdge[]
}>()

const emit = defineEmits<{
  nodeClick: [nodeId: string]
}>()

const chartContainer = ref<HTMLDivElement | null>(null)
const chart = shallowRef<echarts.ECharts | null>(null)

const categoryColorMap: Record<string, string> = {
  '编程语言': '#409eff',
  '框架': '#67c23a',
  '数据库': '#e6a23c',
  '工具': '#909399',
  '算法': '#f56c6c',
  '设计模式': '#9b59b6',
  '网络': '#1abc9c',
  '操作系统': '#e74c3c',
  '前端': '#3498db',
  '后端': '#2ecc71',
  '基础': '#95a5a6',
  default: '#409eff',
}

function getCategories(): { name: string; itemStyle: { color: string } }[] {
  const catSet = new Set<string>()
  for (const node of props.nodes) {
    catSet.add(node.category || '其他')
  }
  return Array.from(catSet).map((cat) => ({
    name: cat,
    itemStyle: {
      color: categoryColorMap[cat] || categoryColorMap['default'] || '#409eff',
    },
  }))
}

function buildOption() {
  const categories = getCategories()
  const categoryNames = categories.map((c) => c.name)

  const graphNodes = props.nodes.map((node) => ({
    id: node.id,
    name: node.name,
    category: categoryNames.indexOf(node.category || '其他'),
    symbolSize: node.difficulty === 'hard' ? 50 : node.difficulty === 'medium' ? 40 : 30,
    label: {
      show: true,
      fontSize: 12,
    },
    value: node.description,
  }))

  const graphEdges = props.edges.map((edge) => ({
    source: edge.source,
    target: edge.target,
    label: {
      show: true,
      formatter: edge.type,
      fontSize: 10,
      color: '#999',
    },
    lineStyle: {
      color: '#ccc',
      curveness: 0.1,
    },
  }))

  return {
    tooltip: {
      trigger: 'item' as const,
      formatter: (params: { dataType: string; name: string; value: string }) => {
        if (params.dataType === 'node') {
          return `<strong>${params.name}</strong><br/>${params.value || ''}`
        }
        return ''
      },
    },
    legend: {
      data: categories.map((c) => c.name),
      orient: 'vertical' as const,
      right: 10,
      top: 20,
      textStyle: {
        fontSize: 12,
        color: '#666',
      },
    },
    animationDuration: 1000,
    animationEasingUpdate: 'quinticInOut',
    series: [
      {
        type: 'graph',
        layout: 'force',
        data: graphNodes,
        links: graphEdges,
        categories,
        roam: true,
        draggable: true,
        force: {
          repulsion: 200,
          edgeLength: [80, 200],
          gravity: 0.1,
        },
        emphasis: {
          focus: 'adjacency' as const,
          lineStyle: {
            width: 3,
          },
        },
        label: {
          show: true,
          position: 'right' as const,
          formatter: '{b}',
        },
        lineStyle: {
          color: 'source',
          curveness: 0.1,
        },
        edgeLabel: {
          show: false,
          fontSize: 10,
        },
      },
    ],
  }
}

function initChart() {
  if (!chartContainer.value) return
  chart.value = echarts.init(chartContainer.value)
  chart.value.setOption(buildOption())

  chart.value.on('click', 'series', (params: { dataType?: string; data?: { id?: string } }) => {
    if (params.dataType === 'node' && params.data?.id) {
      emit('nodeClick', params.data.id)
    }
  })
}

function updateChart() {
  if (chart.value) {
    chart.value.setOption(buildOption(), true)
  }
}

function handleResize() {
  chart.value?.resize()
}

onMounted(() => {
  initChart()
  window.addEventListener('resize', handleResize)
})

onBeforeUnmount(() => {
  window.removeEventListener('resize', handleResize)
  chart.value?.dispose()
})

watch(
  () => [props.nodes, props.edges],
  () => {
    updateChart()
  },
  { deep: true },
)
</script>

<template>
  <div ref="chartContainer" class="graph-renderer" />
</template>

<style lang="scss" scoped>
.graph-renderer {
  width: 100%;
  height: 100%;
  min-height: 400px;
}
</style>","totalLinesInFile":188}

