    private int calculateHealthScore(Long userId) {
        LocalDate today = LocalDate.now();
        LocalDate start = today.minusDays(29);
        List<Map<String, Object>> recentDaily = learningRecordMapper.countByUserIdGroupByDate(
                userId,
                start.atStartOfDay(),
                today.plusDays(1).atStartOfDay()
        );

        int activeDays30 = recentDaily.size();
        int streak = calculateCurrentStreak(recentDaily, today);
        int totalActions30 = recentDaily.stream().mapToInt(m -> ((Number) m.get("count")).intValue()).sum();
        int avgDaily = activeDays30 == 0 ? 0 : Math.round((float) totalActions30 / activeDays30);

        int continuityScore = Math.min(40, activeDays30 * 40 / 20);
        int streakScore = Math.min(30, streak * 5);
        int intensityScore = Math.min(30, avgDaily * 5);

        return Math.min(100, continuityScore + streakScore + intensityScore);
    }

    private int calculateCurrentStreak(List<Map<String, Object>> recentDaily, LocalDate today) {
        Map<String, Integer> dayMap = recentDaily.stream().collect(Collectors.toMap(
                m -> String.valueOf(m.get("date")),
                m -> ((Number) m.get("count")).intValue(),
                (a, b) -> a
        ));

        int streak = 0;
        for (int i = 0; i < 30; i++) {
            LocalDate day = today.minusDays(i);
            if (dayMap.containsKey(day.toString())) {
                streak++;
            } else {
                break;
            }
        }
        return streak;
    }

    private List<WeakAreaVO> buildWeakAreas(Long userId) {
        List<LearningPath> paths = learningPathMapper.selectList(
                new LambdaQueryWrapper<LearningPath>().eq(LearningPath::getUserId, userId)
        );
        if (paths.isEmpty()) {
            return List.of(
                    WeakAreaVO.builder().key("db").name("数据库基础").score(35).suggestion("建议复习 SQL 索引与查询优化").build(),
                    WeakAreaVO.builder().key("algo").name("算法与数据结构").score(40).suggestion("建议每周完成 3 道中等题").build(),
                    WeakAreaVO.builder().key("security").name("后端安全").score(45).suggestion("建议补齐 JWT 与权限控制实践").build()
            );
        }

        Map<String, AreaCounter> areaMap = new HashMap<>();
        for (LearningPath path : paths) {
            List<LearningNode> nodes = learningNodeMapper.selectByPathId(path.getId());
            for (LearningNode node : nodes) {
                String key = classifyArea(node.getKnowledgeId());
                AreaCounter counter = areaMap.computeIfAbsent(key, k -> new AreaCounter(displayAreaName(k)));
                counter.total++;
                if ("done".equalsIgnoreCase(node.getStatus())) {
                    counter.done++;
                }
            }
        }

        return areaMap.entrySet().stream()
                .map(e -> {
                    String key = e.getKey();
                    AreaCounter c = e.getValue();
                    int score = c.total == 0 ? 0 : (int) Math.round((double) c.done * 100 / c.total);
                    return WeakAreaVO.builder()
                            .key(key)
                            .name(c.name)
                            .score(score)
                            .suggestion(buildSuggestion(key, score))
                            .build();
                })
                .sorted(Comparator.comparingInt(WeakAreaVO::getScore))
                .limit(3)
                .collect(Collectors.toList());
    }

    private List<WeeklyPlanItemVO> buildWeeklyPlan(Long userId, List<WeakAreaVO> weakAreas) {
        List<String> completedIds = learningRecordMapper.selectDistinctTargetIdsByUserIdAndActionType(userId, "weekly_plan_done");

        List<WeeklyPlanItemVO> plan = new ArrayList<>();
        for (int i = 0; i < Math.min(3, weakAreas.size()); i++) {
            WeakAreaVO area = weakAreas.get(i);
            String id = "plan:" + area.getKey();
            plan.add(WeeklyPlanItemVO.builder()
                    .id(id)
                    .title("补强「" + area.getName() + "」")
                    .description(buildPlanDescription(area.getKey()))
                    .completed(completedIds.contains(id))
                    .build());
        }

        if (plan.size() < 3) {
            String id = "plan:review";
            plan.add(WeeklyPlanItemVO.builder()
                    .id(id)
                    .title("复盘本周问答与代码片段")
                    .description("整理 5 条高质量问答，沉淀为可复用代码片段")
                    .completed(completedIds.contains(id))
                    .build());
        }

        return plan;
    }

    private String classifyArea(String knowledgeId) {
        String text = knowledgeId == null ? "" : knowledgeId.toLowerCase();
        if (text.contains("mysql") || text.contains("sql") || text.contains("redis") || text.contains("database")) {
            return "db";
        }
        if (text.contains("vue") || text.contains("react") || text.contains("js") || text.contains("front")) {
            return "frontend";
        }
        if (text.contains("spring") || text.contains("java") || text.contains("mybatis") || text.contains("api")) {
            return "backend";
        }
        if (text.contains("docker") || text.contains("k8") || text.contains("devops") || text.contains("deploy")) {
            return "devops";
        }
        return "algorithm";
    }

    private String displayAreaName(String key) {
        return switch (key) {
            case "db" -> "数据库与缓存";
            case "frontend" -> "前端工程";
            case "backend" -> "后端开发";
            case "devops" -> "DevOps 与部署";
            default -> "算法与数据结构";
        };
    }

    private String buildSuggestion(String areaKey, int score) {
        if (score >= 80) {
            return "掌握较好，建议通过项目实战巩固";
        }
        return switch (areaKey) {
            case "db" -> "建议完成 2 次 SQL 优化练习并复习 Redis 缓存策略";
            case "frontend" -> "建议完成 1 个组件重构并补齐状态管理实践";
            case "backend" -> "建议完成 1 个接口设计 + 安全鉴权练习";
            case "devops" -> "建议实践一次 Docker Compose 全链路部署";
            default -> "建议每周完成 3 道中等难度算法题";
        };
    }

    private String buildPlanDescription(String areaKey) {
        return switch (areaKey) {
            case "db" -> "完成 2 次数据库优化实操，并总结索引命中规则";
            case "frontend" -> "完成 1 个页面性能优化，并输出组件复用清单";
            case "backend" -> "完成 1 个鉴权接口与 1 个异常处理优化任务";
            case "devops" -> "完成本地一键部署脚本并验证回滚流程";
            default -> "完成 3 道算法题并整理解题模板";
        };
    }

    private void addTableRow(PdfPTable table, String label, String value, Font labelFont, Font valueFont) {
        PdfPCell labelCell = new PdfPCell(new Phrase(label, labelFont));
        labelCell.setBorderColor(BaseColor.LIGHT_GRAY);
        labelCell.setPadding(8);
        table.addCell(labelCell);

        PdfPCell valueCell = new PdfPCell(new Phrase(value, valueFont));
        valueCell.setBorderColor(BaseColor.LIGHT_GRAY);
        valueCell.setPadding(8);
        valueCell.setHorizontalAlignment(Element.ALIGN_RIGHT);
        table.addCell(valueCell);
    }

