            return List.of(
                    new WeakAreaVO("db", "数据库与缓存", 40, "建议完成 2 次 SQL 优化练习"),
                    new WeakAreaVO("algorithm", "算法与数据结构", 45, "建议每周完成 3 道中等题"),
                    new WeakAreaVO("backend", "后端开发", 50, "建议补齐鉴权和异常处理实践")
            );
        }

        Map<String, int[]> counter = new HashMap<>();
        for (LearningPath path : paths) {
            for (LearningNode node : learningNodeMapper.selectByPathId(path.getId())) {
                String key = areaOf(node.getKnowledgeId());
                int[] arr = counter.computeIfAbsent(key, k -> new int[]{0, 0});
                arr[0]++;
                if ("done".equalsIgnoreCase(node.getStatus())) arr[1]++;
            }
        }

        return counter.entrySet().stream()
                .map(e -> {
                    int total = e.getValue()[0], done = e.getValue()[1];
                    int score = total == 0 ? 0 : (int) Math.round(done * 100.0 / total);
                    return new WeakAreaVO(e.getKey(), areaName(e.getKey()), score, areaSuggestion(e.getKey(), score));
                })
                .sorted(Comparator.comparingInt(WeakAreaVO::getScore))
                .limit(3)
                .collect(Collectors.toList());
    }

    private List<WeeklyPlanItemVO> buildWeeklyPlan(Long userId, List<WeakAreaVO> weakAreas) {
        List<String> done = learningRecordMapper.selectDistinctTargetIdsByUserIdAndActionType(userId, "weekly_plan_done");
        List<WeeklyPlanItemVO> items = new ArrayList<>();
        for (WeakAreaVO area : weakAreas) {
            String id = "plan:" + area.getKey();
            items.add(new WeeklyPlanItemVO(id, "补强「" + area.getName() + "」", planOf(area.getKey()), done.contains(id)));
        }
        while (items.size() < 3) {
            String id = "plan:review" + items.size();
            items.add(new WeeklyPlanItemVO(id, "复盘本周学习", "整理 5 条高质量问答并沉淀为代码片段", done.contains(id)));
        }
        return items.subList(0, 3);
    }

    private String areaOf(String knowledgeId) {
